let gib: UInt64 = 1024 * 1024 * 1024
    if bytes >= gib {
        if bytes % gib == 0 {
            return "\(bytes / gib)G"
        }
        let formatted = String(format: "%.1fG", Double(bytes) / Double(gib))
        if formatted.hasSuffix(".0G") {
            return "\(bytes / gib)G"
        }
        return formatted
    }
    return "\(bytes / (1024 * 1024))M"
